-- Gene Kim (1–14)
(gen_random_uuid(), 'Mejorar el trabajo diario es incluso más importante que hacer el trabajo diario.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'El trabajo no planificado siempre cuesta más que el trabajo planificado.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La deuda técnica es como la deuda financiera. Si no pagas el capital, pagarás intereses para siempre.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Hasta que el código no está en producción, no se genera valor real. Solo es trabajo en progreso atascado en el sistema.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'El mayor riesgo en DevOps es no moverse con suficiente rapidez.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['courage','discipline'], true, 'coding'),
(gen_random_uuid(), 'Esperar la solución perfecta es en sí misma una forma de desperdicio.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'Las restricciones dictan dónde enfocar los esfuerzos de mejora. Encuentra el cuello de botella y explótalo.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La resiliencia se construye practicando el fallo antes de que te ocurra.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','courage'], true, 'coding'),
(gen_random_uuid(), 'El objetivo no es eliminar el cambio, sino poder gestionarlo con elegancia.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La automatización no consiste en reemplazar personas. Consiste en liberar a las personas para trabajo de mayor valor.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'Los lotes pequeños reducen la variabilidad y hacen visibles los problemas antes.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'Todo negocio es un negocio de software. Debes empezar a pensar y actuar como una empresa digital.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'Cuando las cosas salen mal, y siempre lo harán, la pregunta es: ¿con qué rapidez puedes detectar y solucionar el problema?', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El primer camino enfatiza el rendimiento del sistema completo, no el rendimiento de un silo de trabajo específico.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),

-- Jez Humble (15–28)
(gen_random_uuid(), 'El mayor riesgo en el desarrollo de software es construir algo que nadie quiere.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La entrega continua es la capacidad de llevar cambios de todo tipo a producción de forma segura, rápida y sostenible.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'Cada construcción debe estar lista para producción. Si tu software no es desplegable en todo momento, acumulas riesgo.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La integración continua no es una herramienta, es una disciplina.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'Integrar menos frecuentemente no reduce el riesgo, lo aumenta enormemente.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Las pruebas automatizadas son el fundamento de la entrega continua. Sin ellas, nada más funciona.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'El despliegue debe ser un evento aburrido y rutinario, no un momento de terror.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Si duele, hazlo más frecuentemente. El dolor desaparece cuando lo practicas constantemente.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','courage'], true, 'coding'),
(gen_random_uuid(), 'La calidad no se puede inspeccionar a posteriori. Debe construirse desde el inicio.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Un pipeline de despliegue convierte cada commit en un candidato para producción.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'La verdadera agilidad requiere que puedas liberar software en cualquier momento.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Reducir el tamaño de los lotes reduce el riesgo y acelera el feedback.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'El trabajo en progreso es inventario. El inventario es riesgo. Minimiza ambos.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La infraestructura como código permite aplicar las mismas prácticas de ingeniería al aprovisionamiento que al software.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','learning'], true, 'coding'),

-- Patrick Debois (29–41)
(gen_random_uuid(), 'DevOps no es un rol, es una mentalidad de colaboración entre desarrollo y operaciones.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La cultura es el ingrediente más difícil de cambiar en cualquier transformación DevOps.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'Los silos entre dev y ops son la raíz de la mayoría de los problemas de entrega de software.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La empatía entre equipos de desarrollo y operaciones es más valiosa que cualquier herramienta.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Automatizar el despliegue es el primer paso para recuperar el control del proceso de entrega.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'DevOps es el resultado lógico de aplicar pensamiento Agile a las operaciones de TI.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'La confianza entre equipos se construye con transparencia, no con promesas.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El monitoreo no es opcional. Es la diferencia entre reaccionar y anticipar.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Cada incidente es una oportunidad de aprendizaje. Culpar a las personas destruye ese aprendizaje.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'El flujo de valor del software va desde la idea hasta el usuario. DevOps optimiza ese flujo completo.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Compartir el dolor del despliegue entre dev y ops es el primer paso hacia la responsabilidad compartida.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','courage'], true, 'coding'),
(gen_random_uuid(), 'Las retrospectivas sin acción son solo terapia de grupo. La mejora requiere cambios concretos.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'No existe una transformación DevOps sin cambiar la forma en que los equipos se comunican.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),

