(gen_random_uuid(), 'La escalabilidad no es solo un problema técnico. Es también un problema organizacional.', 'Werner Vogels', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Operar a escala significa que los problemas que antes eran hipotéticos se vuelven cotidianos.', 'Werner Vogels', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'La nube no elimina los problemas de infraestructura. Los transforma.', 'Werner Vogels', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
