(gen_random_uuid(), 'Los equipos que poseen sus servicios de extremo a extremo despliegan con más confianza.', 'Werner Vogels', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La resiliencia del sistema se prueba bajo condiciones reales, no en reuniones de planificación.', 'Werner Vogels', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','courage'], true, 'coding'),
(gen_random_uuid(), 'El aislamiento de fallos es una característica de diseño, no una corrección posterior.', 'Werner Vogels', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Los disyuntores en software hacen lo mismo que en electricidad: evitan que un fallo destruya todo el sistema.', 'Werner Vogels', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
