(gen_random_uuid(), 'Depurar en producción no es un pecado. Es una habilidad que todo ingeniero debe dominar.', 'Charity Majors', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['courage','learning'], true, 'coding'),
