(gen_random_uuid(), 'La resiliencia no es la ausencia de fallos. Es la capacidad de recuperarse de ellos con gracia.', 'John Allspaw', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','courage'], true, 'coding'),
