-- Martin Fowler (97–111)
(gen_random_uuid(), 'Cualquier tonto puede escribir código que un computador entiende. Los buenos programadores escriben código que los humanos pueden entender.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La refactorización continua es el mantenimiento preventivo del software. Ignorarla genera deuda técnica acumulada.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
