(gen_random_uuid(), 'Los microservicios son una opción de arquitectura con beneficios y costos reales. No son una solución universal.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Una buena arquitectura maximiza las decisiones que no necesitas tomar hoy.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Las pruebas de integración son más valiosas que las unitarias cuando el contrato entre sistemas es la fuente de bugs.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El trunk-based development reduce la carga cognitiva de gestionar ramas de larga duración.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'Los feature flags permiten separar el despliegue del lanzamiento. Son una herramienta poderosa de gestión de riesgo.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Un monolito bien estructurado es preferible a un conjunto de microservicios mal diseñados.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El código es el único documento que refleja con exactitud lo que el sistema hace realmente.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Los patrones de diseño son vocabulario compartido para discutir soluciones a problemas recurrentes de arquitectura.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'La integración continua es una práctica, no una herramienta. Las herramientas solo la facilitan.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
