(gen_random_uuid(), 'La arquitectura evolutiva acepta que los requisitos cambiarán y diseña para facilitar ese cambio.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
