-- Eric Raymond (112–122)
(gen_random_uuid(), 'Con suficientes ojos, todos los bugs son superficiales. La revisión abierta es el mejor sistema de control de calidad.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'Lanza pronto, lanza frecuentemente. Escucha a tus usuarios y desarrolla en abierto.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','courage'], true, 'coding'),
