(gen_random_uuid(), 'Documenta el por qué, no el qué. El código ya explica el qué. El comentario debe explicar la intención.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Los mejores programas crecen desde necesidades reales, no desde especificaciones abstractas.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'La modularidad reduce la complejidad. Cada módulo debe tener una responsabilidad clara y una interfaz pequeña.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),

