(gen_random_uuid(), 'La portabilidad real del software requiere empaquetar no solo el código sino también el entorno de ejecución.', 'Solomon Hykes', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),

-- Adrian Cockcroft (189–200)
(gen_random_uuid(), 'Netflix demostró que los microservicios a escala masiva son viables con la arquitectura correcta.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'La ingeniería del caos no es sabotaje. Es la práctica de descubrir debilidades antes de que el caos real las encuentre.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','courage'], true, 'coding'),
(gen_random_uuid(), 'La arquitectura de microservicios requiere madurez operacional que los equipos pequeños a menudo subestiman.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Los servicios bien diseñados tienen límites claros que mapean con precisión a las capacidades del negocio.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La nube no es solo infraestructura. Es una plataforma que cambia la forma en que construyes y operas software.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'Los equipos de dos pizzas de Amazon son la expresión organizacional del principio de responsabilidad única.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La degradación elegante es más valiosa que la disponibilidad total. Decide qué puede fallar sin destruir la experiencia.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Los patrones de resiliencia como bulkheads y circuit breakers son la arquitectura de la tolerancia a fallos.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La velocidad de despliegue es una métrica de salud organizacional, no solo técnica.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El monitoreo distribuido requiere correlacionar eventos de múltiples fuentes. El trazado distribuido hace esto posible.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Las organizaciones que adoptan la nube solo para ahorrar costos pierden sus beneficios más importantes.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La agilidad en la nube proviene de la capacidad de experimentar rápidamente con nuevas arquitecturas sin inversión masiva.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','courage'], true, 'coding'),

-- Richard Stallman (201–208)
(gen_random_uuid(), 'El software libre no significa que no cueste dinero. Significa que el usuario tiene libertad sobre él.', 'Richard Stallman', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','courage'], true, 'coding'),
(gen_random_uuid(), 'Copyleft es la forma de usar el copyright para garantizar que el software libre permanezca libre.', 'Richard Stallman', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La libertad de estudiar cómo funciona un programa y adaptarlo es fundamental para el conocimiento técnico.', 'Richard Stallman', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'La infraestructura crítica construida sobre software propietario crea dependencias que vulneran la soberanía tecnológica.', 'Richard Stallman', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','courage'], true, 'coding'),
(gen_random_uuid(), 'Compartir el código es el acto más natural de cooperación entre programadores. Las restricciones artificiales son el problema.', 'Richard Stallman', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'GNU fue una demostración de que un sistema completo puede construirse por cooperación voluntaria sin jerarquía corporativa.', 'Richard Stallman', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','courage'], true, 'coding'),
(gen_random_uuid(), 'Las cuatro libertades del software libre son las bases de una infraestructura tecnológica soberana y auditable.', 'Richard Stallman', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El derecho a modificar el software que usas es tan fundamental como el derecho a reparar los objetos que posees.', 'Richard Stallman', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','courage'], true, 'coding'),

-- Larry Wall (209–215)
(gen_random_uuid(), 'Las tres virtudes del programador son la pereza, la impaciencia y la arrogancia. En ese orden preciso.', 'Larry Wall', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Hay más de una forma de hacerlo. La flexibilidad en el diseño de lenguajes permite expresividad real.', 'Larry Wall', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'Perl fue diseñado para hacer fácil las cosas fáciles y posible las cosas difíciles, no para hacer todo igual de difícil.', 'Larry Wall', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La automatización de tareas repetitivas es la primera aplicación de la pereza productiva del programador.', 'Larry Wall', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'Los scripts de shell son el pegamento que une las herramientas de UNIX en flujos de trabajo automatizados.', 'Larry Wall', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El procesamiento de texto es el trabajo central del sistema operativo. Dominarlo es dominar la automatización.', 'Larry Wall', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Un lenguaje de scripting es el martillo del administrador de sistemas. Úsalo para clavar automatización en todas partes.', 'Larry Wall', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),

-- Guido van Rossum (216–223)
(gen_random_uuid(), 'El código es leído con mucha más frecuencia de lo que es escrito. Optimiza para la lectura, no para la escritura.', 'Guido van Rossum', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Debería haber una y, preferiblemente solo una, forma obvia de hacerlo. La claridad tiene valor práctico.', 'Guido van Rossum', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Explícito es mejor que implícito. En infraestructura como en código, la claridad previene errores costosos.', 'Guido van Rossum', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Los errores nunca deben pasar silenciosamente. A menos que sean silenciados explícitamente. La opacidad mata.', 'Guido van Rossum', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Si la implementación es difícil de explicar, es una mala idea. La complejidad oculta cobra facturas altas.', 'Guido van Rossum', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Python fue diseñado con la legibilidad como objetivo primario porque los programas son comunicación entre humanos.', 'Guido van Rossum', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'La automatización con Python en DevOps demostró que la legibilidad y la utilidad práctica no son opuestos.', 'Guido van Rossum', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Frente a la ambigüedad, rechaza la tentación de adivinar. Pregunta explícitamente o falla con claridad.', 'Guido van Rossum', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),

-- General DevOps / CI-CD topics — attributed as community wisdom (224–250)
(gen_random_uuid(), 'Un pipeline roto es una señal de alarma, no un inconveniente. Detente, corrígelo, no lo ignores.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'El despliegue azul-verde elimina el tiempo de inactividad al tener dos entornos de producción idénticos intercambiables.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El despliegue canario reduce el riesgo exponiendo el cambio a una fracción pequeña de usuarios antes del rollout completo.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Los logs estructurados son más valiosos que los logs de texto libre. Formatea para que las máquinas puedan leerlos.', 'Charity Majors', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'El trazado distribuido es la herramienta que hace comprensibles los sistemas de microservicios en producción.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los objetivos de nivel de servicio son contratos con los usuarios. Defínelos antes de construir, no después de fallar.', 'Werner Vogels', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El presupuesto de error es la cantidad de tiempo de inactividad aceptable que queda antes de violar el SLO.', 'John Allspaw', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La automatización de pruebas de seguridad en el pipeline convierte la seguridad en una propiedad continua del sistema.', 'Kelsey Hightower', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'La gestión de secretos es el problema de seguridad más subestimado en la infraestructura moderna de software.', 'Mitchell Hashimoto', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El análisis de causa raíz que termina en "error humano" es un análisis incompleto. El sistema permitió ese error.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','learning'], true, 'coding'),
(gen_random_uuid(), 'La revisión de arquitectura no es un proceso burocrático. Es la forma en que los equipos maduros evitan errores costosos.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El reintento con backoff exponencial es el patrón básico para construir resiliencia en llamadas a servicios remotos.', 'Werner Vogels', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Las pruebas de contrato entre servicios garantizan que los cambios en un servicio no rompan silenciosamente a sus consumidores.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'La idempotencia de las operaciones de infraestructura permite ejecutarlas múltiples veces con el mismo resultado seguro.', 'Mitchell Hashimoto', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El monorepo y el repositorio múltiple son estrategias con tradeoffs reales. Elige según la estructura del equipo.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Las migraciones de base de datos son despliegues. Trátales con el mismo rigor que el código de aplicación.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El escaneo de vulnerabilidades en imágenes de contenedores debe ocurrir en el pipeline, no en producción.', 'Solomon Hykes', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'La política de retención de logs no es un detalle técnico menor. Es un requisito de cumplimiento y diagnóstico.', 'Charity Majors', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El auto-escalado reactivo responde al pasado. El auto-escalado predictivo se adelanta al futuro. Ambos tienen su lugar.', 'Adrian Cockcroft', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Las pruebas de carga revelan los límites del sistema antes de que los usuarios reales los descubran por ti.', 'John Allspaw', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'DevSecOps es la integración de la seguridad como práctica continua, no como auditoría de último momento.', 'Patrick Debois', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La documentación de arquitectura como código, con diagramas generados automáticamente, nunca queda desactualizada.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El registro de cambios de infraestructura debe ser tan detallado como el historial de commits del código de aplicación.', 'Kelsey Hightower', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'La observabilidad de costos en la nube es tan importante como la observabilidad técnica. Instrumenta el gasto.', 'Werner Vogels', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Los dashboards que nadie mira son ruido visual. Construye paneles que respondan preguntas operacionales reales.', 'Charity Majors', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','focus'], true, 'coding'),
(gen_random_uuid(), 'La cultura DevOps no se compra con herramientas. Se cultiva con prácticas repetidas y responsabilidad compartida.', 'Gene Kim', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El tiempo de recuperación de un fallo es la métrica más honesta de la madurez operacional de un equipo.', 'Jez Humble', 'philosophy', 'es', 'down', 'free', false, 'coding', 'devops_tools', ARRAY['discipline','courage'], true, 'coding')

